import { useStore } from '../store/useStore';
import { Settings, Layers, Maximize, Hash, Minus } from 'lucide-react';

function ConfigRow({ label, icon: Icon, children }: { label: string; icon: React.ElementType; children: React.ReactNode }) {
  return (
    <div className="flex items-center justify-between py-2">
      <div className="flex items-center gap-2 text-sm text-slate-700">
        <Icon className="h-4 w-4 text-slate-400" />
        {label}
      </div>
      <div className="flex items-center gap-2">{children}</div>
    </div>
  );
}

function NumberInput({ value, min, max, onChange }: { value: number; min: number; max: number; onChange: (v: number) => void }) {
  return (
    <input
      type="number"
      min={min}
      max={max}
      value={value}
      onChange={(e) => onChange(Number(e.target.value))}
      className="w-16 px-2 py-1 text-sm text-right border border-slate-200 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-200 font-mono"
    />
  );
}

function Switch({ checked, onChange }: { checked: boolean; onChange: (v: boolean) => void }) {
  return (
    <button
      onClick={() => onChange(!checked)}
      className={`relative inline-flex h-5 w-9 items-center rounded-full transition-colors ${checked ? 'bg-indigo-500' : 'bg-slate-300'}`}
    >
      <span className={`inline-block h-3.5 w-3.5 transform rounded-full bg-white transition-transform ${checked ? 'translate-x-5' : 'translate-x-1'}`} />
    </button>
  );
}

export function ConfigPanel() {
  const config = useStore((s) => s.config);
  const setConfig = useStore((s) => s.setConfig);

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4 space-y-1">
      <div className="flex items-center gap-2 pb-2 mb-2 border-b border-slate-100">
        <Settings className="h-4 w-4 text-indigo-500" />
        <h3 className="text-sm font-semibold text-slate-800">参数配置</h3>
      </div>

      <ConfigRow label="重叠区域" icon={Layers}>
        <NumberInput
          value={config.overlapMm}
          min={0}
          max={50}
          onChange={(v) => setConfig({ overlapMm: v })}
        />
        <span className="text-xs text-slate-400 w-8">mm</span>
      </ConfigRow>

      <ConfigRow label="四周边距" icon={Maximize}>
        <NumberInput
          value={config.marginMm}
          min={0}
          max={20}
          onChange={(v) => setConfig({ marginMm: v })}
        />
        <span className="text-xs text-slate-400 w-8">mm</span>
      </ConfigRow>

      <ConfigRow label="页码边距" icon={Hash}>
        <NumberInput
          value={config.pageNumberMarginMm}
          min={0}
          max={20}
          onChange={(v) => setConfig({ pageNumberMarginMm: v })}
        />
        <span className="text-xs text-slate-400 w-8">mm</span>
      </ConfigRow>

      <div className="border-t border-slate-100 mt-2 pt-2 space-y-1">
        <ConfigRow label="显示页码" icon={Hash}>
          <Switch checked={config.showPageNumber} onChange={(v) => setConfig({ showPageNumber: v })} />
        </ConfigRow>

        <ConfigRow label="裁切虚线" icon={Minus}>
          <Switch checked={config.showGuideLine} onChange={(v) => setConfig({ showGuideLine: v })} />
        </ConfigRow>
      </div>
    </div>
  );
}
