import { useStore } from '../store/useStore';
import { Download, FileArchive, FileImage } from 'lucide-react';
import JSZip from 'jszip';

export function DownloadBar() {
  const pages = useStore((s) => s.pages);
  const imageInfo = useStore((s) => s.imageInfo);

  const downloadPage = (page: typeof pages[0]) => {
    const link = document.createElement('a');
    link.href = page.dataUrl;
    link.download = `page_${String(page.index).padStart(2, '0')}.jpg`;
    link.click();
  };

  const downloadAll = async () => {
    if (pages.length === 0) return;
    const zip = new JSZip();
    const folder = zip.folder('split_pages');
    if (!folder) return;

    for (const page of pages) {
      const res = await fetch(page.dataUrl);
      const blob = await res.blob();
      folder.file(`page_${String(page.index).padStart(2, '0')}.jpg`, blob);
    }

    const content = await zip.generateAsync({ type: 'blob' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(content);
    link.download = `${imageInfo?.name?.replace(/\.[^/.]+$/, '') || 'split'}_pages.zip`;
    link.click();
    URL.revokeObjectURL(link.href);
  };

  if (pages.length === 0) return null;

  return (
    <div className="bg-white rounded-xl border border-slate-200 p-4">
      <div className="flex flex-col gap-3">
        <div className="flex items-center gap-2">
          <Download className="h-4 w-4 text-indigo-500" />
          <h3 className="text-sm font-semibold text-slate-800">下载</h3>
          <span className="text-xs text-slate-500">共 {pages.length} 页</span>
        </div>
        <div className="flex flex-col w-full gap-2">
          <button
            onClick={() => downloadPage(pages[0])}
            className="flex items-center justify-center gap-1.5 px-3 py-2 text-sm border border-slate-200 rounded-lg hover:bg-slate-50 text-slate-700 transition-colors"
          >
            <FileImage className="h-3.5 w-3.5" />
            下载当前页
          </button>
          <button
            onClick={downloadAll}
            className="flex items-center justify-center gap-1.5 px-3 py-2 text-sm bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 transition-colors"
          >
            <FileArchive className="h-3.5 w-3.5" />
            打包下载 ZIP
          </button>
        </div>
      </div>
    </div>
  );
}
