import { useRef, useEffect, useState } from 'react';
import { ChevronLeft, ChevronRight, ZoomIn, ZoomOut, Eye, Loader2 } from 'lucide-react';
import { useStore } from '../store/useStore';
import { useImageSplitter } from '../hooks/useImageSplitter';

export function PreviewArea() {
  const image = useStore((s) => s.image);
  const pages = useStore((s) => s.pages);
  const imageInfo = useStore((s) => s.imageInfo);
  const config = useStore((s) => s.config);

  const [currentPage, setCurrentPage] = useState(0);
  const [scale, setScale] = useState(0.3);
  const [isProcessing, setIsProcessing] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  const { splitImage } = useImageSplitter((current, total) => {
    setProgress({ current, total });
  });

  // 图片或配置变化时重新拆分
  useEffect(() => {
    if (image) {
      setIsProcessing(true);
      setProgress({ current: 0, total: 0 });
      splitImage().then(() => {
        setIsProcessing(false);
      });
      setCurrentPage(0);
    }
  }, [image, config.overlapMm, config.marginMm, config.pageNumberMarginMm, config.showGuideLine, config.showPageNumber]);

  // 默认自适应整页视图
  useEffect(() => {
    if (pages.length > 0 && containerRef.current) {
      const containerWidth = containerRef.current.clientWidth - 48;
      const imgWidth = pages[0].canvas.width;
      const newScale = Math.min(1, containerWidth / imgWidth);
      setScale(newScale);
    }
  }, [pages]);

  const page = pages[currentPage];

  const handlePrev = () => setCurrentPage((p) => Math.max(0, p - 1));
  const handleNext = () => setCurrentPage((p) => Math.min(pages.length - 1, p + 1));

  const progressPercent = progress.total > 0 ? Math.round((progress.current / progress.total) * 100) : 0;

  return (
    <div className="bg-white rounded-xl border border-slate-200 flex flex-col h-full">
      <div className="flex items-center justify-between px-4 py-3 border-b border-slate-100">
        <div className="flex items-center gap-2">
          <Eye className="h-4 w-4 text-indigo-500" />
          <h3 className="text-sm font-semibold text-slate-800">预览</h3>
        </div>
        {pages.length > 0 && (
          <div className="flex items-center gap-1">
            <button onClick={handlePrev} disabled={currentPage === 0} className="p-1 rounded hover:bg-slate-100 disabled:opacity-30">
              <ChevronLeft className="h-4 w-4" />
            </button>
            <span className="text-xs font-mono text-slate-600 min-w-[60px] text-center">
              {currentPage + 1} / {pages.length}
            </span>
            <button onClick={handleNext} disabled={currentPage === pages.length - 1} className="p-1 rounded hover:bg-slate-100 disabled:opacity-30">
              <ChevronRight className="h-4 w-4" />
            </button>
          </div>
        )}
      </div>

      <div ref={containerRef} className="flex-1 overflow-auto bg-slate-50 flex items-center justify-center p-4 relative">
        {isProcessing ? (
          <div className="flex flex-col items-center justify-center gap-4 w-full max-w-xs">
            <Loader2 className="h-8 w-8 text-indigo-500 animate-spin" />
            <div className="w-full">
              <div className="flex justify-between text-xs text-slate-600 mb-1.5">
                <span>正在拆分...</span>
                <span className="font-mono">{progressPercent}%</span>
              </div>
              <div className="w-full bg-slate-200 rounded-full h-2">
                <div
                  className="bg-indigo-500 h-2 rounded-full transition-all duration-200"
                  style={{ width: `${progressPercent}%` }}
                />
              </div>
              <p className="text-xs text-slate-400 text-center mt-1.5">
                {progress.current} / {progress.total} 页
              </p>
            </div>
          </div>
        ) : page ? (
          <div
            className="relative bg-white shadow-lg rounded-sm overflow-hidden"
            style={{
              width: `min(100%, ${containerRef.current ? containerRef.current.clientHeight * (210 / 297) - 32 : 400}px)`,
              aspectRatio: '210 / 297',
            }}
          >
            <img
              src={page.dataUrl}
              alt={`第 ${page.index} 页`}
              className="w-full h-full object-contain"
            />
          </div>
        ) : imageInfo ? (
          <div className="flex items-center justify-center h-full text-slate-400 text-sm">准备中...</div>
        ) : (
          <div
            className="bg-white border-2 border-dashed border-slate-200 rounded-sm flex items-center justify-center text-slate-400 text-sm"
            style={{ width: '100%', maxWidth: '360px', aspectRatio: '210 / 297' }}
          >
            请先上传图片
          </div>
        )}
      </div>

      {page && (
        <div className="flex items-center justify-center gap-2 px-4 py-2 border-t border-slate-100">
          <button onClick={() => setScale((s) => Math.max(0.1, s - 0.05))} className="p-1.5 rounded hover:bg-slate-100">
            <ZoomOut className="h-4 w-4 text-slate-500" />
          </button>
          <span className="text-xs font-mono text-slate-500 w-12 text-center">{Math.round(scale * 100)}%</span>
          <button onClick={() => setScale((s) => Math.min(1, s + 0.05))} className="p-1.5 rounded hover:bg-slate-100">
            <ZoomIn className="h-4 w-4 text-slate-500" />
          </button>
        </div>
      )}
    </div>
  );
}
