import { useCallback } from 'react';
import { useStore } from '../store/useStore';

export function useImageSplitter(onProgress?: (current: number, total: number) => void) {
  const image = useStore((s) => s.image);
  const config = useStore((s) => s.config);
  const setPages = useStore((s) => s.setPages);

  const splitImage = useCallback(async () => {
    if (!image) return;

    const w = image.naturalWidth;
    const h = image.naturalHeight;
    const { overlapMm, marginMm, pageNumberMarginMm, showGuideLine, showPageNumber, a4Ratio } = config;

    const marginPx = Math.round(marginMm * w / 210);
    const overlapPx = Math.round(overlapMm * w / 210);
    const pageNumPadding = Math.round(pageNumberMarginMm * w / 210);
    const pageHeight = Math.round(w * a4Ratio);
    const step = pageHeight - overlapPx;
    const pageCount = Math.ceil((h - overlapPx) / step);

    const pages = [];
    onProgress?.(0, pageCount);

    for (let i = 0; i < pageCount; i++) {
      const top = i * step;
      const cropHeight = Math.min(pageHeight, h - top);

      // 内容画布
      const contentCanvas = document.createElement('canvas');
      contentCanvas.width = w;
      contentCanvas.height = pageHeight;
      const contentCtx = contentCanvas.getContext('2d')!;

      // 白色背景
      contentCtx.fillStyle = '#ffffff';
      contentCtx.fillRect(0, 0, w, pageHeight);

      // 绘制裁剪内容
      contentCtx.drawImage(image, 0, top, w, cropHeight, 0, 0, w, cropHeight);

      // 虚线（第2页及以后）
      if (showGuideLine && i >= 1 && overlapPx > 0) {
        contentCtx.strokeStyle = '#808080';
        contentCtx.lineWidth = 2;
        contentCtx.setLineDash([15, 10]);
        contentCtx.beginPath();
        contentCtx.moveTo(0, overlapPx);
        contentCtx.lineTo(w, overlapPx);
        contentCtx.stroke();
        contentCtx.setLineDash([]);
      }

      // 边距画布
      let finalCanvas = contentCanvas;
      if (marginPx > 0) {
        const cw = w + 2 * marginPx;
        const ch = pageHeight + 2 * marginPx;
        const canvas = document.createElement('canvas');
        canvas.width = cw;
        canvas.height = ch;
        const ctx = canvas.getContext('2d')!;
        ctx.fillStyle = '#ffffff';
        ctx.fillRect(0, 0, cw, ch);
        ctx.drawImage(contentCanvas, marginPx, marginPx);
        finalCanvas = canvas;
      }

      // 页码
      if (showPageNumber) {
        const ctx = finalCanvas.getContext('2d')!;
        const text = `${i + 1} / ${pageCount}`;
        const fontSize = Math.max(20, Math.round(w / 50));
        ctx.font = `${fontSize}px sans-serif`;
        ctx.fillStyle = '#404040';
        const metrics = ctx.measureText(text);
        const tw = metrics.width;
        const x = finalCanvas.width - tw - pageNumPadding;
        const y = finalCanvas.height - pageNumPadding;
        ctx.fillText(text, x, y);
      }

      const dataUrl = finalCanvas.toDataURL('image/jpeg', 0.95);
      pages.push({ index: i + 1, canvas: finalCanvas, dataUrl });
      onProgress?.(i + 1, pageCount);

      // 让出主线程，使 UI 有机会更新进度
      if (i < pageCount - 1) {
        await new Promise((resolve) => requestAnimationFrame(resolve));
      }
    }

    setPages(pages);
  }, [image, config, setPages, onProgress]);

  return { splitImage };
}
