import { create } from 'zustand';

export interface ConfigState {
  overlapMm: number;
  marginMm: number;
  pageNumberMarginMm: number;
  showGuideLine: boolean;
  showPageNumber: boolean;
  a4Ratio: number;
}

export interface SplitPage {
  index: number;
  canvas: HTMLCanvasElement;
  dataUrl: string;
}

export interface ImageInfo {
  width: number;
  height: number;
  name: string;
}

interface AppState {
  image: HTMLImageElement | null;
  imageInfo: ImageInfo | null;
  config: ConfigState;
  pages: SplitPage[];
  setImage: (img: HTMLImageElement, info: ImageInfo) => void;
  setConfig: (config: Partial<ConfigState>) => void;
  setPages: (pages: SplitPage[]) => void;
}

export const useStore = create<AppState>((set) => ({
  image: null,
  imageInfo: null,
  config: {
    overlapMm: 20,
    marginMm: 5,
    pageNumberMarginMm: 5,
    showGuideLine: false,
    showPageNumber: true,
    a4Ratio: 297 / 210,
  },
  pages: [],
  setImage: (img, info) => set({ image: img, imageInfo: info }),
  setConfig: (config) => set((state) => ({ config: { ...state.config, ...config } })),
  setPages: (pages) => set({ pages }),
}));
