import { useRef, useCallback } from 'react';
import { Upload, Image as ImageIcon } from 'lucide-react';
import { useStore } from '../store/useStore';

export function ImageUploader() {
  const inputRef = useRef<HTMLInputElement>(null);
  const setImage = useStore((s) => s.setImage);
  const imageInfo = useStore((s) => s.imageInfo);

  const handleFile = useCallback((file: File) => {
    if (!file.type.startsWith('image/')) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        setImage(img, {
          width: img.naturalWidth,
          height: img.naturalHeight,
          name: file.name,
        });
      };
      img.src = e.target?.result as string;
    };
    reader.readAsDataURL(file);
  }, [setImage]);

  const onDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    const file = e.dataTransfer.files[0];
    if (file) handleFile(file);
  }, [handleFile]);

  const onChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) handleFile(file);
  }, [handleFile]);

  return (
    <div className="space-y-3">
      <div
        onDrop={onDrop}
        onDragOver={(e) => e.preventDefault()}
        onClick={() => inputRef.current?.click()}
        className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center cursor-pointer hover:border-indigo-400 hover:bg-indigo-50/50 transition-colors"
      >
        <Upload className="mx-auto h-10 w-10 text-slate-400 mb-3" />
        <p className="text-sm text-slate-600 font-medium">点击或拖拽上传长图</p>
        <p className="text-xs text-slate-400 mt-1">支持 JPG、PNG 等常见格式</p>
        <input
          ref={inputRef}
          type="file"
          accept="image/*"
          className="hidden"
          onChange={onChange}
        />
      </div>

      {imageInfo && (
        <div className="flex items-center gap-3 bg-slate-50 rounded-lg p-3">
          <ImageIcon className="h-5 w-5 text-indigo-500" />
          <div className="flex-1 min-w-0">
            <p className="text-sm font-medium text-slate-700 truncate">{imageInfo.name}</p>
            <p className="text-xs text-slate-500 font-mono">
              {imageInfo.width} x {imageInfo.height} px
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
